  render: () => <AdminShell title='Admin Forms' subtitle='Create / edit flows with preview and dialogs'>\r
      <Stack spacing={2}>\r
        <Breadcrumbs content='Create item' showBackButton />\r
\r
        <Paper variant='outlined' sx={{
        borderRadius: 2,
        overflow: 'hidden'
      }}>\r
          <Box sx={{
          p: 2,
          borderBottom: '1px solid #eaecf0',
          display: 'flex',
          alignItems: 'center'
        }}>\r
            <Box sx={{
            flex: 1
          }}>\r
              <Typography variant='subtitle1' sx={{
              fontWeight: 900
            }}>\r
                Basic info\r
              </Typography>\r
              <Typography variant='caption' color='text.secondary'>\r
                Required fields, validation, and preview.\r
              </Typography>\r
            </Box>\r
            <Stack direction='row' spacing={1}>\r
              <ButtonElement variant='outlined' content='Cancel' onClick={fn()} />\r
              <ButtonElement variant='contained' content='Save' onClick={fn()} />\r
            </Stack>\r
          </Box>\r
\r
          <Box sx={{
          display: 'grid',
          gridTemplateColumns: {
            xs: '1fr',
            md: '7fr 5fr'
          },
          alignItems: 'stretch'
        }}>\r
            <Box sx={{
            p: 2
          }}>\r
              <Stack spacing={2}>\r
                <TextFieldElement label='Name' placeholder='Enter name...' required showResetButton />\r
                <TextFieldElement label='Email' placeholder='Enter email...' iconLabel='mail' showResetButton />\r
                <TextFieldElement label='Description' placeholder='Multiline...' rows={3} showResetButton={false} />\r
                <Stack direction='row' spacing={2} alignItems='center' justifyContent='space-between'>\r
                  <CheckboxElement label='Active' onChange={fn()} />\r
                  <Stack direction='row' spacing={1} alignItems='center'>\r
                    <Typography variant='caption' color='text.secondary'>\r
                      Notifications\r
                    </Typography>\r
                    <SwitchElement value={true} onChange={fn()} />\r
                  </Stack>\r
                </Stack>\r
              </Stack>\r
            </Box>\r
\r
            <Box sx={{
            borderLeft: {
              xs: 'none',
              md: '1px solid #eaecf0'
            }
          }}>\r
              <Box sx={{
              p: 2
            }}>\r
                <Typography variant='subtitle2' sx={{
                fontWeight: 900,
                mb: 1
              }}>\r
                  Preview\r
                </Typography>\r
                <TypographyInfoUser columns={1} items={[{
                label: 'Full name',
                value: 'Nguyễn Văn A'
              }, {
                label: 'Department',
                value: 'Engineering'
              }, {
                label: 'Phone',
                value: ''
              }, {
                label: 'Email',
                value: 'a.nguyen@example.com'
              }]} highlightQuery='eng' />\r
              </Box>\r
            </Box>\r
          </Box>\r
        </Paper>\r
\r
        <Paper variant='outlined' sx={{
        borderRadius: 2,
        p: 2
      }}>\r
          <Typography variant='subtitle2' sx={{
          fontWeight: 900,
          mb: 1
        }}>\r
            Dialog examples (closed by default)\r
          </Typography>\r
          <Stack direction='row' spacing={1}>\r
            <DialogElement label='Dialog title' open={false} onClose={fn()} nodeContent={<Typography variant='body2'>Dialog content</Typography>} buttonRight={{
            content: 'Close',
            onClick: fn()
          }} />\r
            <DialogConfirmActionElement open={false} title='Confirm action' description='Are you sure?' closeText='Cancel' confirmText='Confirm' confirmColor={'error' as any} closeColor={'info' as any} onClose={fn()} onConfirm={fn()} />\r
          </Stack>\r
        </Paper>\r
      </Stack>\r
    </AdminShell>
